// Treasure Chest — pirate chest with weathered walnut wood + gold hardware
// Z-up, front (-Y), right-handed. Returns a single Manifold.
// Design: solid wood box/dome (wood-dominant), gold hardware as accents.

const { Manifold, CrossSection } = api;
const { label } = api;

// ---------------------------------------------------------------------------
// Dimensions
// ---------------------------------------------------------------------------
const W  = 26;    // width  (X)
const D  = 15;    // depth  (Y)
const BH = 11;    // body height Z = 0..BH
const LR = 7.2;   // lid dome radius
const LZ = BH;    // dome axis at z = BH

const FY = -D / 2;  // front face Y
const BY =  D / 2;  // back face Y
const LX = -W / 2;  // left face X
const RX =  W / 2;  // right face X

const PR  = 0.55;   // proud (protrudes from face)
const SK  = 0.80;   // sink (into wood — ensures volumetric union)
const SW  = 1.7;    // strap height/width

// ---------------------------------------------------------------------------
// Wood body & lid
// ---------------------------------------------------------------------------
const body = Manifold.cube([W, D, BH], true)
  .translate([0, 0, BH / 2]);

const lid = (() => {
  const cyl = Manifold.cylinder(W, LR, LR, 48)
    .rotate([0, 90, 0])
    .translate([-W / 2, 0, LZ]);
  const cut = Manifold.cube([W + 4, D * 4, LR + 2], true)
    .translate([0, 0, LZ - (LR + 2) / 2]);
  return cyl.subtract(cut);
})();

// ---------------------------------------------------------------------------
// Continuous perimeter rims at base and seam — the structural frame
// These thin rims hold everything together visually; they're narrow enough
// that wood is clearly the dominant material between them.
// ---------------------------------------------------------------------------
function perimeterRim(zCenter, rimH) {
  const dep = SK + PR;
  // Front + back full-width strip
  const fb = Manifold.cube([W + PR * 2, dep, rimH], true);
  const front = fb.translate([0, FY + dep / 2 - PR, zCenter]);
  const back  = fb.translate([0, BY - dep / 2 + PR, zCenter]);
  // Side strips (narrow between front/back)
  const ss = Manifold.cube([dep, D - 0, rimH], true);
  const sL = ss.translate([LX + dep / 2 - PR, 0, zCenter]);
  const sR = ss.translate([RX - dep / 2 + PR, 0, zCenter]);
  return Manifold.union([front, back, sL, sR]);
}

const topRim  = perimeterRim(BH + 0.4, 1.3);
const baseRim = perimeterRim(0.5,      1.1);

// ---------------------------------------------------------------------------
// Mid-body perimeter ring — single wrap at body mid-height for structural read
// This gives the chest a "cinched" look without dominating both faces
// ---------------------------------------------------------------------------
function midRing(zC) {
  const dep = SK + PR;
  const h = SW;
  const front = Manifold.cube([W + PR * 2, dep, h], true)
    .translate([0, FY + dep / 2 - PR, zC]);
  const back  = Manifold.cube([W + PR * 2, dep, h], true)
    .translate([0, BY - dep / 2 + PR, zC]);
  const sL = Manifold.cube([dep, D, h], true)
    .translate([LX + dep / 2 - PR, 0, zC]);
  const sR = Manifold.cube([dep, D, h], true)
    .translate([RX - dep / 2 + PR, 0, zC]);
  return Manifold.union([front, back, sL, sR]);
}
const midBand = midRing(5.5);  // single mid-body ring


// ---------------------------------------------------------------------------
// Front face vertical straps — 3 bands running full front height + up lid
// ---------------------------------------------------------------------------
// 3 dome band positions — center one aligns with lock/hasp
const BAND_X = [-8.5, 0, 8.5];
// Vertical strap positions: only outer 2 (center is reserved for lock/hasp column)
const VERT_X = [-8.5, 8.5];

function frontVert(x) {
  const dep = SK + PR;
  // Body portion
  return Manifold.cube([SW, dep, BH + SW / 2], true)
    .translate([x, FY + dep / 2 - PR, BH / 2 + SW / 4]);
}
// All 3 front verticals — center one integrates with lock/hasp cluster
const frontVerts = Manifold.union(BAND_X.map(frontVert));

// Back face verticals for symmetry
function backVert(x) {
  const dep = SK + PR;
  return Manifold.cube([SW, dep, BH + SW / 2], true)
    .translate([x, BY - dep / 2 + PR, BH / 2 + SW / 4]);
}
const backVerts = Manifold.union(BAND_X.map(backVert));

// ---------------------------------------------------------------------------
// Dome arc bands — 3 curved arcs over the lid dome (front+top)
// ---------------------------------------------------------------------------
function arcBand(x) {
  const rOut = LR + PR;
  const rIn  = LR - SK;
  const outer = Manifold.cylinder(SW, rOut, rOut, 32);
  const inner = Manifold.cylinder(SW + 2, rIn, rIn, 32).translate([0, 0, -1]);
  let ring = outer.subtract(inner);
  ring = ring.rotate([0, 90, 0]).translate([x - SW / 2, 0, LZ]);
  // clip to upper half only
  const clip = Manifold.cube([SW + 2, (rOut + 1) * 2, rOut + 2], true)
    .translate([x, 0, LZ + (rOut + 2) / 2]);
  return ring.intersect(clip);
}
const domeBands = Manifold.union(BAND_X.map(arcBand));

// Seam tabs: connectors from dome bands down to body at seam — all 3 positions
function seamTab(x) {
  const dep = SK + PR;
  const th  = 3.6;
  const f = Manifold.cube([SW, dep, th], true)
    .translate([x, FY + dep / 2 - PR, LZ + th / 2 - 1.0]);
  const b = Manifold.cube([SW, dep, th], true)
    .translate([x, BY - dep / 2 + PR, LZ + th / 2 - 1.0]);
  return Manifold.union([f, b]);
}
const seamTabs = Manifold.union(BAND_X.map(seamTab));

// ---------------------------------------------------------------------------
// Corner reinforcements — angled metal caps, tall on body corners
// ---------------------------------------------------------------------------
function corner(sx, sy) {
  const t  = 1.3;
  const fl = t + PR;
  const h  = BH + 0.5;
  const xfl = Manifold.cube([fl, t, h], true)
    .translate([sx * (W / 2 - fl / 2 + PR), sy * (D / 2 - t / 2), BH / 2]);
  const yfl = Manifold.cube([t, fl, h], true)
    .translate([sx * (W / 2 - t / 2), sy * (D / 2 - fl / 2 + PR), BH / 2]);
  return Manifold.union([xfl, yfl]);
}
const corners = Manifold.union([
  corner(-1, -1), corner(1, -1),
  corner(-1,  1), corner(1,  1),
]);

// ---------------------------------------------------------------------------
// Feet — 4 flattened ball feet at base corners
// ---------------------------------------------------------------------------
function foot(sx, sy) {
  const fr = 1.7;
  return Manifold.sphere(fr, 16)
    .scale([1, 1, 0.60])
    .translate([
      sx * (W / 2 - 1.0),
      sy * (D / 2 - 1.0),
      fr * 0.60 - 0.38,
    ]);
}
const feet = Manifold.union([
  foot(-1, -1), foot(1, -1),
  foot(-1,  1), foot(1,  1),
]);

// ---------------------------------------------------------------------------
// Lock plate — prominently raised, centered on front face
// ---------------------------------------------------------------------------
const PW  = 5.4;
const PH  = 6.0;
const PPR = 1.3;
const PSK = 1.1;
const PD  = PPR + PSK;
const PCY = FY - PPR + PD / 2;
const PZ  = BH * 0.50;

// Main rectangular plate
let plate = Manifold.cube([PW, PD, PH], true)
  .translate([0, PCY, PZ]);

// Arched top
const pTop = Manifold.cylinder(PD, PW / 2, PW / 2, 16)
  .rotate([90, 0, 0])
  .translate([0, PCY + PD / 2 - 0.01, PZ + PH / 2]);
plate = Manifold.union([plate, pTop]);

// Keyhole (round hole + downward slot)
// Bore must stay WITHIN the plate proud zone (not reach body front face at FY)
// Plate front face: FY - PPR = -8.8; body front face: FY = -7.5
// Bore from -8.9 (slightly in front of plate) to -8.9 + PPR = -7.6 (< -7.5 = body face)
const KD  = PPR;               // bore depth = plate proud thickness
const KY  = FY - PPR - 0.1;   // start just in front of plate face
const KZ  = PZ + 0.3;
const khRound = Manifold.cylinder(KD, 0.85, 0.85, 16)
  .rotate([-90, 0, 0])
  .translate([0, KY, KZ + 0.5]);
const khSlot = Manifold.cube([0.7, KD, 2.3], true)
  .translate([0, KY + KD / 2 - 0.01, KZ - 0.6]);
plate = plate.subtract(Manifold.union([khRound, khSlot]));

// Corner rivets
function rivet(rx, rz) {
  return Manifold.sphere(0.38, 8).translate([rx, FY - 0.1, rz]);
}
const rivets = Manifold.union([
  rivet(-PW / 2 + 0.6, PZ - PH / 2 + 0.6),
  rivet( PW / 2 - 0.6, PZ - PH / 2 + 0.6),
  rivet(-PW / 2 + 0.6, PZ + PH / 2 - 0.6),
  rivet( PW / 2 - 0.6, PZ + PH / 2 - 0.6),
]);
plate = Manifold.union([plate, rivets]);

// ---------------------------------------------------------------------------
// Hasp — slim rectangular strap bridging seam (same depth as lock plate)
// Narrower than lock plate; runs vertically up from lock toward top of dome
// ---------------------------------------------------------------------------
const HW  = 2.2;   // narrower than plate
const HPR = PPR;   // same proud as plate
const HSK = PSK;
const HD  = HPR + HSK;
const HCY = FY - HPR + HD / 2;
const hasp = Manifold.cube([HW, HD, 4.8], true)
  .translate([0, HCY, LZ + 1.2]);

const lockGroup = Manifold.union([plate, hasp]);

// ---------------------------------------------------------------------------
// Assemble all gold hardware
// ---------------------------------------------------------------------------
const allTrim = Manifold.union([
  topRim, baseRim,
  frontVerts,  backVerts,
  domeBands,   seamTabs,
  corners,     feet,
]);

// ---------------------------------------------------------------------------
// Label and union
// ---------------------------------------------------------------------------
const bodyLab = label(body,      'body');
const lidLab  = label(lid,       'lid');
const trimLab = label(allTrim,   'trim');
const lockLab = label(lockGroup, 'lock');

const whole = Manifold.union([bodyLab, lidLab, trimLab, lockLab]);

// ---------------------------------------------------------------------------
// Surface textures — woven grain on wood regions
// ---------------------------------------------------------------------------
api.surface.woven({ amplitude: 0.42, threadSpacing: 3.0, quality: 0.7, label: 'body' });
api.surface.woven({ amplitude: 0.42, threadSpacing: 3.0, quality: 0.7, label: 'lid' });

// ---------------------------------------------------------------------------
// Colors — deep walnut wood + warm gleaming brass/gold
// ---------------------------------------------------------------------------
api.paint.label('body', [0.290, 0.168, 0.038]);  // rich dark walnut
api.paint.label('lid',  [0.252, 0.143, 0.031]);  // darker lid
api.paint.label('trim', [0.784, 0.580, 0.039]);  // tarnished brass
api.paint.label('lock', [0.875, 0.658, 0.062]);  // bright gold

return whole;
